// makeInternalIterOpts builds the internalIterOpts for the point iterator
// stack and initializes the iterator's blob value fetcher when a blob mapping
// exists. Shared by V1 and V2 construction paths.
func (i *Iterator) makeInternalIterOpts(memtables flushableList) internalIterOpts {
	readEnv := block.ReadEnv{
		Stats: &i.stats.InternalStats,
		// If the file cache has a sstable stats collector, ask it for an
		// accumulator for this iterator's configured category and QoS. All SSTable
		// iterators created by this Iterator will accumulate their stats to it as
		// they Close during iteration.
		IterStats: i.fc.SSTStatsCollector().Accumulator(
			uint64(uintptr(unsafe.Pointer(i))),
			i.opts.Category,
		),
		ValueRetrievalProfile: i.valueRetrievalProfile,
	}

	// Determine the blob file mapping. We may need to combine the version's
	// BlobFileSet with blob files from ingestedFlushables in the memtable queue.
	var maxReadAmp int
	var versionBlobFiles *manifest.BlobFileSet
	if i.readState != nil {
		versionBlobFiles = &i.readState.current.BlobFiles
		maxReadAmp = i.readState.current.MaxReadAmp()
	} else if i.version != nil {
		versionBlobFiles = &i.version.BlobFiles
		maxReadAmp = i.version.MaxReadAmp()
	}
	if i.combinedBlobMapping.Init(
		versionBlobFiles, memtables,
	) {
		i.blobValueFetcher.Init(&i.combinedBlobMapping, i.fc, readEnv,
			blob.SuggestedCachedReaders(maxReadAmp))
	}

	internalOpts := internalIterOpts{
		readEnv:          sstable.ReadEnv{Block: readEnv},
		blobValueFetcher: &i.blobValueFetcher,
	}
	if i.opts.RangeKeyMasking.Filter != nil {
		internalOpts.boundLimitedFilter = &i.rangeKeyMasking
	}
	return internalOpts
}

